function createAnimState() {
  return {
    weaponRecoil: 0,
    recoilFrames: 0,
    weaponVisible: true,
    flashIntensity: 0,
    flashX: 0,
    flashY: 0,
    charRecoil: 0,
    charShakeX: 0,
    charShakeY: 0,
    charHitFlash: 0,
    screenFlash: 0,
    chromaShift: 0,
    screenShakeX: 0,
    screenShakeY: 0,
    clickDrop: 0,
    charArmRaise: 0,
    charGunRecoil: 0,
    charSelfAim: 0,
    jedPoseOverride: null,
    effects: [],
    bannerKey: null,
    bannerFrames: 0,
  };
}

function createNpcReactionState() {
  return {
    silas: "idle",
    joe: "playing",
    drifter: "idle",
    silasFlinchFrames: 0,
    joeFlinchFrames: 0,
    drifterIntentFrames: 0,
  };
}

function resetNpcReactions(state) {
  state.silas = "idle";
  state.joe = "playing";
  state.drifter = "idle";
  state.silasFlinchFrames = 0;
  state.joeFlinchFrames = 0;
  state.drifterIntentFrames = 0;
}

function applyNpcGunshotReaction(state, eventType) {
  if (eventType === "blank") {
    state.silas = "flinch";
    state.joe = "flinch";
    state.drifter = "intent";
    state.silasFlinchFrames = 20;
    state.joeFlinchFrames = 30;
    state.drifterIntentFrames = 20;
    return;
  }
  if (eventType === "jed_hit" || eventType === "player_hit") {
    state.silas = "ducking";
    state.joe = "ducking";
    state.drifter = "standing";
    state.silasFlinchFrames = 0;
    state.joeFlinchFrames = 0;
    state.drifterIntentFrames = 0;
  }
}

function updateNpcReactions(state) {
  if (state.silasFlinchFrames > 0) {
    state.silasFlinchFrames -= 1;
    if (state.silasFlinchFrames <= 0 && state.silas === "flinch") state.silas = "idle";
  }
  if (state.joeFlinchFrames > 0) {
    state.joeFlinchFrames -= 1;
    if (state.joeFlinchFrames <= 0 && state.joe === "flinch") state.joe = "playing";
  }
  if (state.drifterIntentFrames > 0) {
    state.drifterIntentFrames -= 1;
    if (state.drifterIntentFrames <= 0 && state.drifter === "intent") state.drifter = "idle";
  }
}

