function createImage(src) {
  if (typeof Image === "undefined") return null;
  const img = new Image();
  img.decoding = "async";
  img.src = src;
  return img;
}

function createSpriteMap(sources) {
  return Object.fromEntries(Object.entries(sources).map(([key, src]) => [key, createImage(src)]));
}

const SPRITES = createSpriteMap({ ...SPRITE_MANIFEST, ...V2_SPRITE_MANIFEST });
