    setDoubleDamage(false); doubleDamageRef.current = false;
    setPlayerItems([]);
    setOpponentItems([]); opponentItemsRef.current = [];
    setAnimating(false); animatingRef.current = false;
    setIsPlayerTurn(true); isPlayerTurnRef.current = true;
    gamePhaseRef.current = null;
