    if (!LEGAL_ITEM_IDS.has(item.id)) { console.error(`[item_use] Illegal item id "${item.id}" blocked.`); return; }
    if (item.id === "beer" && shellsRef.current.length === 0) { addMsg("No shell loaded.", "system"); return; }
